def closest_pair(points):
    points.sort()

    def dist2(p, q):
        return (p[0]-q[0])**2 + (p[1]-q[1])**2

    def solve(pts):
        n = len(pts)
        if n <= 3:
            md = float('inf')
            pair = None
            for i in range(n):
                for j in range(i+1, n):
                    d = dist2(pts[i], pts[j])
                    if d < md:
                        md, pair = d, (pts[i], pts[j])
            return md, pair, sorted(pts, key=lambda p: p[1])

        mid = n // 2
        mid_x = pts[mid][0]
        dl, pair_l, y_left = solve(pts[:mid])
        dr, pair_r, y_right = solve(pts[mid:])

        d = min(dl, dr)
        best_pair = pair_l if dl <= dr else pair_r

        i = j = 0
        y_merged = []
        while i < len(y_left) and j < len(y_right):
            if y_left[i][1] <= y_right[j][1]:
                y_merged.append(y_left[i]); i += 1
            else:
                y_merged.append(y_right[j]); j += 1
        y_merged.extend(y_left[i:])
        y_merged.extend(y_right[j:])

        strip = [p for p in y_merged if abs(p[0] - mid_x) < math.sqrt(d)]
        for i in range(len(strip)):
            for j in range(i+1, min(i+7, len(strip))):
                if (strip[j][1] - strip[i][1])**2 >= d:
                    break
                dd = dist2(strip[i], strip[j])
                if dd < d:
                    d = dd
                    best_pair = (strip[i], strip[j])

        return d, best_pair, y_merged

    _, pair, _ = solve(points)
    return pair

double closestPair(vector<pair<int,int>>& points) {
    sort(points.begin(), points.end());
    auto dist2 = [](pair<int,int> p, pair<int,int> q) {
        return (long long)(p.first-q.first)*(p.first-q.first) + (long long)(p.second-q.second)*(p.second-q.second);
    };
    function<double(vector<pair<int,int>>&)> solve = [&](vector<pair<int,int>>& pts) -> double {
        int n = pts.size();
        if (n <= 3) {
            double md = 1e18;
            for (int i = 0; i < n; i++)
                for (int j = i+1; j < n; j++)
                    md = min(md, (double)dist2(pts[i], pts[j]));
            return md;
        }
        int mid = n / 2;
        double midX = pts[mid].first;
        vector<pair<int,int>> left(pts.begin(), pts.begin()+mid);
        vector<pair<int,int>> right(pts.begin()+mid, pts.end());
        double dl = solve(left), dr = solve(right);
        double d = min(dl, dr);
        vector<pair<int,int>> yMerged;
        merge(left.begin(), left.end(), right.begin(), right.end(), back_inserter(yMerged),
              [](auto& a, auto& b) { return a.second < b.second; });
        vector<pair<int,int>> strip;
        for (auto& p : yMerged)
            if (abs(p.first - midX) < sqrt(d))
                strip.push_back(p);
        for (int i = 0; i < (int)strip.size(); i++)
            for (int j = i+1; j < min(i+7, (int)strip.size()); j++) {
                if ((strip[j].second - strip[i].second)*(strip[j].second - strip[i].second) >= d) break;
                d = min(d, (double)dist2(strip[i], strip[j]));
            }
        return d;
    };
    return sqrt(solve(points));
}

