        while (upper.size() >= 2 && cross(upper.get(upper.size()-2), upper.get(upper.size()-1), p) <= 0)
            upper.remove(upper.size()-1);
        upper.add(p);
    }
    lower.remove(lower.size()-1);
    upper.remove(upper.size()-1);
    lower.addAll(upper);
    return lower;
}

function convexHull(points) {
    points = [...new Set(points.map(p => p[0] + ',' + p[1]))].map(s => s.split(',').map(Number));
    points.sort((a, b) => a[0] !== b[0] ? a[0] - b[0] : a[1] - b[1]);
    if (points.length <= 1) return points;
    function cross(o, a, b) {
        return (a[0] - o[0]) * (b[1] - o[1]) - (a[1] - o[1]) * (b[0] - o[0]);
    }
    const lower = [];
    for (const p of points) {
        while (lower.length >= 2 && cross(lower[lower.length-2], lower[lower.length-1], p) <= 0)
            lower.pop();
        lower.push(p);
    }
    const upper = [];
    for (const p of points.reverse()) {
        while (upper.length >= 2 && cross(upper[upper.length-2], upper[upper.length-1], p) <= 0)
            upper.pop();
        upper.push(p);
    }
    lower.pop();
    upper.pop();
    return lower.concat(upper);
}

def point_in_convex_polygon(point, hull):
    """hull in CCW order. O(log N)."""
    n = len(hull)
    if n < 3: return False

    o = orientation(hull[0], hull[1], point)
    if o < 0: return False
    if o == 0: return on_segment(hull[0], point, hull[1])

    lo, hi = 1, n
    while hi - lo > 1:
        mid = (lo + hi) // 2
        if orientation(hull[0], hull[mid], point) >= 0:
            lo = mid
        else:
            hi = mid

    if lo == n - 1:
        return on_segment(hull[0], point, hull[n-1])

    return orientation(hull[lo], hull[lo+1], point) >= 0

bool pointInConvexPolygon(vector<int> point, vector<vector<int>>& hull) {
    int n = hull.size();
    if (n < 3) return false;
    long long o = orientation(hull[0], hull[1], point);
    if (o < 0) return false;
    if (o == 0) return onSegment(hull[0], point, hull[1]);
    int lo = 1, hi = n;
    while (hi - lo > 1) {
        int mid = (lo + hi) / 2;
        if (orientation(hull[0], hull[mid], point) >= 0) lo = mid;
        else hi = mid;
    }
    if (lo == n - 1) return onSegment(hull[0], point, hull[n-1]);
    return orientation(hull[lo], hull[lo+1], point) >= 0;
}

long long orientation(vector<int> p, vector<int> q, vector<int> r) {
    return (long long)(q[0]-p[0]) * (r[1]-p[1]) - (long long)(q[1]-p[1]) * (r[0]-p[0]);
}

bool onSegment(vector<int> p, vector<int> q, vector<int> r) {
    return min(p[0], r[0]) <= q[0] && q[0] <= max(p[0], r[0]) &&
           min(p[1], r[1]) <= q[1] && q[1] <= max(p[1], r[1]);
}

