}
static boolean onSegment(int[] p, int[] q, int[] r) {
    return Math.min(p[0], r[0]) <= q[0] && q[0] <= Math.max(p[0], r[0]) &&
           Math.min(p[1], r[1]) <= q[1] && q[1] <= Math.max(p[1], r[1]);
}

function pointInConvexPolygon(point, hull) {
    const n = hull.length;
    if (n < 3) return false;
    const o = orientation(hull[0], hull[1], point);
    if (o < 0) return false;
    if (o === 0) return onSegment(hull[0], point, hull[1]);
    let lo = 1, hi = n;
    while (hi - lo > 1) {
        const mid = Math.floor((lo + hi) / 2);
        if (orientation(hull[0], hull[mid], point) >= 0) lo = mid;
        else hi = mid;
    }
    if (lo === n - 1) return onSegment(hull[0], point, hull[n-1]);
    return orientation(hull[lo], hull[lo+1], point) >= 0;
}

def commando(N, a, b, c, xs):
    prefix = [0] * (N + 1)
    for i in range(N):
        prefix[i+1] = prefix[i] + xs[i]

    dp = [0] * (N + 1)
    from collections import deque
    dq = deque([0])

    def value(j, x):
        return (-2*a*prefix[j]) * x + (a*prefix[j]**2 - b*prefix[j] + dp[j])

    def cross(l1, l2, l3):
        a1 = -2*a*prefix[l1]; b1 = a*prefix[l1]**2 - b*prefix[l1] + dp[l1]
        a2 = -2*a*prefix[l2]; b2 = a*prefix[l2]**2 - b*prefix[l2] + dp[l2]
        a3 = -2*a*prefix[l3]; b3 = a*prefix[l3]**2 - b*prefix[l3] + dp[l3]
        return (b2 - b1) * (a3 - a2) >= (b3 - b2) * (a2 - a1)

    for i in range(1, N + 1):
        while len(dq) >= 2 and value(dq[0], prefix[i]) <= value(dq[1], prefix[i]):
            dq.popleft()
        j = dq[0]
        x = prefix[i] - prefix[j]
        dp[i] = dp[j] + a*x*x + b*x + c

        while len(dq) >= 2 and cross(dq[-2], dq[-1], i):
            dq.pop()
        dq.append(i)

    return dp[N]

long long commando(int N, long long a, long long b, long long c, vector<long long>& xs) {
    vector<long long> prefix(N+1, 0);
    for (int i = 0; i < N; i++) prefix[i+1] = prefix[i] + xs[i];
    vector<long long> dp(N+1, 0);
    deque<int> dq;
    dq.push_back(0);
    auto value = [&](int j, long long x) {
        return (-2*a*prefix[j]) * x + (a*prefix[j]*prefix[j] - b*prefix[j] + dp[j]);
    };
    auto cross = [&](int l1, int l2, int l3) {
        __int128 a1 = -2*a*prefix[l1]; __int128 b1 = a*prefix[l1]*prefix[l1] - b*prefix[l1] + dp[l1];
        __int128 a2 = -2*a*prefix[l2]; __int128 b2 = a*prefix[l2]*prefix[l2] - b*prefix[l2] + dp[l2];
        __int128 a3 = -2*a*prefix[l3]; __int128 b3 = a*prefix[l3]*prefix[l3] - b*prefix[l3] + dp[l3];
        return (b2 - b1) * (a3 - a2) >= (b3 - b2) * (a2 - a1);
    };
    for (int i = 1; i <= N; i++) {
        while (dq.size() >= 2 && value(dq[0], prefix[i]) <= value(dq[1], prefix[i]))
            dq.pop_front();
        int j = dq[0];
        long long x = prefix[i] - prefix[j];
        dp[i] = dp[j] + a*x*x + b*x + c;
        while (dq.size() >= 2 && cross(dq[dq.size()-2], dq.back(), i))
            dq.pop_back();
        dq.push_back(i);
    }
    return dp[N];
}

public static long commando(int N, long a, long b, long c, int[] xs) {
    long[] prefix = new long[N+1];
    for (int i = 0; i < N; i++) prefix[i+1] = prefix[i] + xs[i];
    long[] dp = new long[N+1];
    Deque<Integer> dq = new ArrayDeque<>();
    dq.addLast(0);
    for (int i = 1; i <= N; i++) {
        while (dq.size() >= 2 && value(dq.peekFirst(), dq.peekFirst()+1, prefix[i], prefix, dp, a, b))
            dq.pollFirst();
        int j = dq.peekFirst();
        long x = prefix[i] - prefix[j];
        dp[i] = dp[j] + a*x*x + b*x + c;
        while (dq.size() >= 2 && cross(dq.get(dq.size()-2), dq.getLast(), i, prefix, dp, a))
            dq.pollLast();
        dq.addLast(i);
    }
    return dp[N];
}
static boolean value(int j1, int j2, long x, long[] prefix, long[] dp, long a, long b) {
    return (-2*a*prefix[j1])*x + (a*prefix[j1]*prefix[j1] - b*prefix[j1] + dp[j1]) <=
           (-2*a*prefix[j2])*x + (a*prefix[j2]*prefix[j2] - b*prefix[j2] + dp[j2]);
}
static boolean cross(int l1, int l2, int l3, long[] prefix, long[] dp, long a) {
    long a1 = -2*a*prefix[l1], b1 = a*prefix[l1]*prefix[l1] + dp[l1];
    long a2 = -2*a*prefix[l2], b2 = a*prefix[l2]*prefix[l2] + dp[l2];
    long a3 = -2*a*prefix[l3], b3 = a*prefix[l3]*prefix[l3] + dp[l3];
    return (b2 - b1) * (a3 - a2) >= (b3 - b2) * (a2 - a1);
}

function commando(N, a, b, c, xs) {
    const prefix = new Array(N+1).fill(0);
    for (let i = 0; i < N; i++) prefix[i+1] = prefix[i] + xs[i];
    const dp = new Array(N+1).fill(0);
    const dq = [0];
    function value(j, x) {
        return (-2*a*prefix[j]) * x + (a*prefix[j]**2 - b*prefix[j] + dp[j]);
    }
    function cross(l1, l2, l3) {
        const a1 = -2*a*prefix[l1], b1 = a*prefix[l1]**2 - b*prefix[l1] + dp[l1];
        const a2 = -2*a*prefix[l2], b2 = a*prefix[l2]**2 - b*prefix[l2] + dp[l2];
        const a3 = -2*a*prefix[l3], b3 = a*prefix[l3]**2 - b*prefix[l3] + dp[l3];
        return (b2 - b1) * (a3 - a2) >= (b3 - b2) * (a2 - a1);
    }
    for (let i = 1; i <= N; i++) {
        while (dq.length >= 2 && value(dq[0], prefix[i]) <= value(dq[1], prefix[i]))
            dq.shift();
        const j = dq[0];
        const x = prefix[i] - prefix[j];
        dp[i] = dp[j] + a*x*x + b*x + c;
        while (dq.length >= 2 && cross(dq[dq.length-2], dq[dq.length-1], i))
            dq.pop();
        dq.push(i);
    }
    return dp[N];
}
